from ._version import __version__  # noqa: F403,F401

if os.name == "nt":  # pragma: no cover
    os.environ["PATH"] = (
        f"{os.path.abspath(os.path.dirname(__file__))}"
        f"{os.pathsep}"
        f"{os.environ['PATH']}"
    )

_pango_available = False
try:
    from .register_font import *  # isort:skip # noqa: F403,F401
    from .cmanimpango import *  # noqa: F403,F401
    from .enums import *  # noqa: F403,F401
    _pango_available = True
except (ImportError, OSError):
    # iOS: .so frameworks may not load on first run or may need re-deploy.
    # Provide stub fallbacks so manim can still work with Cairo renderer.
    import warnings
    warnings.warn("ManimPango native libs unavailable; using stub fallbacks for Cairo rendering.", stacklevel=2)

    # Stub enums
    class PangoUtils:
        @staticmethod
        def str2style(s): return 0
        @staticmethod
        def str2weight(s): return 400
        @staticmethod
        def remove_last_M(s): return s

    class Style:
        NORMAL = 0
        ITALIC = 1
        OBLIQUE = 2

    class Weight:
        NORMAL = 400
        BOLD = 700
        THIN = 100
        LIGHT = 300
        BOOK = 380
        MEDIUM = 500
        SEMIBOLD = 600
        ULTRABOLD = 800
        HEAVY = 900
        ULTRAHEAVY = 1000

    # Stub text layout using CoreText via basic measurement
    class TextSetting:
        def __init__(self, start=0, end=0, font='', slant='NORMAL', weight='NORMAL',
                     line_num=0, is_new_line=False):
            self.start = start
            self.end = end
            self.font = font
            self.slant = slant
            self.weight = weight
            self.line_num = line_num
            self.is_new_line = is_new_line

    def text2svg(text, font='', slant='NORMAL', weight='NORMAL', size=1,
                 _line_spacing=-1, disable_ligatures=False, **kwargs):
        """Stub text→SVG using basic SVG text element."""
        fs = max(size * 10, 12)
        esc = text.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')
        w = len(text) * fs * 0.6
        h = fs * 1.4
        return (f'<svg xmlns="http://www.w3.org/2000/svg" width="{w}" height="{h}">'
                f'<text x="0" y="{fs}" font-family="{font or "Helvetica"}" '
                f'font-size="{fs}" fill="white">{esc}</text></svg>')

    def markup2svg(text, font='', slant='NORMAL', weight='NORMAL', size=1,
                   _line_spacing=-1, disable_ligatures=False, **kwargs):
        """Stub markup→SVG (strips Pango markup, renders as plain text)."""
        import re
        plain = re.sub(r'<[^>]+>', '', text)
        return text2svg(plain, font, slant, weight, size, _line_spacing, disable_ligatures, **kwargs)

    def list_fonts():
        """Return empty font list (no fontconfig on iOS)."""
        return []

    def register_font(font_path):
        return True

    def unregister_font(font_path):
        return True

    registered_fonts = set()

    class RegisteredFont:
        def __init__(self, path=''):
            self.path = path

    class Variant:
        NORMAL = 0
        SMALL_CAPS = 1

    class Alignment:
        LEFT = 0
        CENTER = 1
        RIGHT = 2

    class MarkupUtils:
        @staticmethod
        def validate(markup):
            """Stub: validate Pango markup. Returns empty string (valid) on iOS."""
            return ""

        @staticmethod
        def text2svg(text, font=None, slant='NORMAL', weight='NORMAL', size=1,
                     _line_spacing=-1, disable_ligatures=False, file_name='',
                     START_X=0, START_Y=0, width=600, height=400, *,
                     justify=None, indent=None, line_spacing=None,
                     alignment=None, pango_width=None):
            """Stub markup text->SVG using basic SVG text element."""
            import re
            plain = re.sub(r'<[^>]+>', '', text)
            fs = max(size * 10, 12)
            esc = plain.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')
            w = width
            h = height
            svg_content = (
                f'<svg xmlns="http://www.w3.org/2000/svg" width="{w}" height="{h}">'
                f'<text x="{START_X}" y="{START_Y + fs}" '
                f'font-family="{font or "Helvetica"}" '
                f'font-size="{fs}" fill="white">{esc}</text></svg>'
            )
            if file_name:
                with open(file_name, 'w') as f:
                    f.write(svg_content)
                return file_name
            return svg_content

    def pango_version():
        """Stub: return placeholder Pango version on iOS."""
        return "1.50.0"

    def cairo_version():
        """Stub: return placeholder Cairo version on iOS."""
        return "1.16.0"

    __all__ = [
        'PangoUtils', 'Style', 'Weight', 'Variant', 'Alignment',
        'TextSetting', 'MarkupUtils',
        'text2svg', 'markup2svg', 'list_fonts',
        'register_font', 'unregister_font', 'registered_fonts', 'RegisteredFont',
        'pango_version', 'cairo_version',
    ]
